[Form]
public class ETGPurchRateCard extends FormRun
{
    [FormObservable]
    InventMovement                  movement;
    [FormObservable]
    InventTransWMS_Register         inventTransWMS_Register;
    InventDimCtrl_Frm_Mov_InventWMS inventDimFormSetup;

    QueryBuildRange                 rangeChildType;
    QueryBuildRange                 rangeChildRefId;

    boolean                         salesReturnMode;
    SalesLine                       salesReturnLine;
    PurchLine                       callerPurchLine;

    boolean                         tmpTransCreated;
    PdsCWFormCtrl_InventTransRegister   cwFormCtrl;
    boolean                         pdsUseVendUpdated;
    PdsUpdBatchDate                 pdsBlankDateQuest;
    boolean                         pdsUpdBlankBatchDate;

    Common                          callerRecord;
    boolean                         attribValRequired;
    PdsBatchAttrib                  pdsBatchAttrib;

    #ISOCountryRegionCodes
    boolean                         countryRegion_RU;
    PurchParmLine                   callerPurchParmLine;
    boolean                         calledFromPurchaseOrder, calledFromProductReceipt;



}

/// <summary>
/// Delegate raised after <c>TmpInventTransWMS</c> data source is set to enabled.
/// </summary>
/// <param name = "_fromCreate">Indicates whether the data source is set to enabled during creation process.</param>
delegate void tmpInventTransWMSSetEnabled(boolean _fromCreate)
{
}

public void activate(boolean _active)
{
    if (#PdsShelfEnabled)
    {
        element.pdsShow();
    }

    super(_active);
}

public boolean canClose()
{
    boolean ret;

    if (tmpinventTransWMS.RecId)
    {
        if (Box::yesNo("Rate card is not applied. If you close this form your changes will not be save. Do you want to continue?" ,
            DialogButton::Yes) != DialogButton::Yes)
        {
            return false;
        }
    }
    ret = super();

    return ret;
}

void doRefresh()
{
    InventTrans           pmfInventTrans;

    pmfInventTrans = inventTrans.data();
    inventTrans_ds.research();
    inventTrans_ds.positionToRecord(pmfInventTrans);
}

public void doResearch(boolean _resetTmpInventTransWMS = false)
{
    InventTrans findInventTrans = inventTrans.data();

    inventTrans_ds.research();
    inventTrans_ds.positionToRecord(findInventTrans);

    tmpInventTransWMS_dS.setEnabled(false);

    if (_resetTmpInventTransWMS)
    {
        if (inventTransWMS_Register)
        {
            inventTransWMS_Register.makeTableEmpty();
        }

        tmpInventTransWMS_ds.research();
    }

    ctrlTransactions.setFocus();
}

public void init()
{

    super();

    if (!element.args().dataset())
    {
        throw error(strFmt("@SYS22678",element.name()));
    }

    callerRecord = element.args().record();

    if (element.args() && element.args().dataset() == tableNum(PurchLine))
    {
        calledFromPurchaseOrder = true;
        callerPurchLine = element.args().record() as PurchLine;
        this.canRateCardApply();
        ETGPurchRateCardApplyRate.visible(true);
    }
    if (element.args() && element.args().dataset() == tableNum(PurchParmLine))
    {
        calledFromProductReceipt = true;
        callerPurchParmLine = element.args().record() as PurchParmLine;
        callerPurchLine     = callerPurchParmLine.purchLine();
        this.canRateCardApply();
        ETGPurchRateCardApplyRate.visible(false);
    }

    this.validateRateCard();
}

public void canRateCardApply()
{
    ETGRateCardMaster rateCardMaster;

    if(!callerPurchLine.MatchingAgreementLine)
    {
        throw Error(strFmt("Rate card not be applied. Matching agreement line does not exists for purchase order %1 and item %2", callerPurchLine.PurchId, callerPurchLine.ItemId));
    }
    //select firstonly RecId from rateCardMaster 
    //    where rateCardMaster.RefRecId == callerPurchLine.MatchingAgreementLine
    //    && rateCardMaster.IsConfirmed == NoYes::Yes;
    //{
    //    if(!rateCardMaster.RecId)
    //    {
    //        throw Error(strFmt("Rate card not be applied. Confirmed rate card master does not exists for purchase order %1 and item %2", callerPurchLine.PurchId, callerPurchLine.ItemId));
    //    }
    //}
}

public void validateRateCard()
{
    PurchLine     purchLineLoc;

    select firstonly RecId from purchLineLoc
            where purchLineLoc.PurchId == callerPurchLine.PurchId
                && purchLineLoc.ItemId == callerPurchLine.ItemId
                && purchLineLoc.ETGRateCardApplied == NoYes::Yes;

    if(purchLineLoc.RecId)
    {
        warning(strFmt("Rate card is already applied for item %1", callerPurchLine.ItemId));
        element.close();
    }
}

public Object inventDimSetupObject()
{
    return inventDimFormSetup;
}

public InventTransWMS_Register inventTransWMS_Register(boolean _forceNew = false)
{
    if (!inventTransWMS_Register || _forceNew)
    {
        inventTransWMS_Register = InventTransWMS_Register::newStandard(tmpInventTransWMS);
    }

    return inventTransWMS_Register;
}

public InventMovement movement()
{
    if (!movement)
    {
        movement = InventTransWMS_Register::inventMovement(element.args().record());
    }

    return movement;
}

