/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    Query query = new Query();
    QueryBuildDataSource qbds;
    QueryBuildRange qbr, qbr1, qbr2;
    SysTableLookup  sysTableLookup = SysTableLookup::newParameters(tableNum(ETGRateCardMaster), _formControl);

    qbds = query.addDataSource(tableNum(ETGRateCardMaster));
    //qbr1  = SysQuery::findOrCreateRange(qbds, fieldNum(ETGRateCardMaster, IsConfirmed));
    //qbr1.value(queryValue(NoYes::Yes));
    //qbr1.status(RangeStatus::Hidden);

    qbr2  = SysQuery::findOrCreateRange(qbds, fieldNum(ETGRateCardMaster, RefRecId));
    qbr2.value(queryValue(callerPurchLine.MatchingAgreementLine));
    qbr2.status(RangeStatus::Hidden);

    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, RateCardId), true);
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, ItemId));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, configId));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, InventSizeId));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, InventColorId));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, InventStyleId));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, DiscPct));
    sysTableLookup.addLookupfield(fieldNum(ETGRateCardMaster, DiscAmount));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

public void modified()
{
    ETGRateCardMaster rateCardMaster;
    LineAmount        priceAfterCashDisc, priceAfterDiscPercent;
    DiscPct           totalDiscPct;

    super();

    select firstonly rateCardMaster where rateCardMaster.RateCardId == TmpInventTransWMS.ETGDisplayProductNumber;

    if(!rateCardMaster)
    {
        throw error("Rate card details not found");
    }

    TmpInventTransWMS.ItemId                = rateCardMaster.ItemId;
    TmpInventTransWMS.ETGRetailVariantId    = rateCardMaster.RetailVariantId;
    TmpInventDim.configId                   = rateCardMaster.configId;
    TmpInventDim.InventSizeId               = rateCardMaster.InventSizeId;
    TmpInventDim.InventColorId              = rateCardMaster.InventColorId;
    TmpInventDim.InventStyleId              = rateCardMaster.InventStyleId;

    if(ETGcanadaparameters::find().EnableRateCardChanges)
    {
        TmpInventDim.inventSerialId             = InventTable::find(rateCardMaster.ItemId).ETGDefaultSerialNumber;
    }

    if(callerPurchLine)
    {
        TmpInventTransWMS.ETGRateCardUnitPrice  = callerPurchLine.PurchPrice;
        TmpInventTransWMS.InventQty             = callerPurchLine.PurchQty;
        priceAfterCashDisc                      = callerPurchLine.PurchPrice;
        priceAfterCashDisc                      = callerPurchLine.PurchPrice - (rateCardMaster.DiscAmount + callerPurchLine.LineDisc);
        TmpInventTransWMS.ETGRateCardDiscAmount = rateCardMaster.DiscAmount + callerPurchLine.LineDisc;
        TmpInventTransWMS.ETGRateCardLineAmount = priceAfterCashDisc * callerPurchLine.PurchQty;
        totalDiscPct                            = rateCardMaster.DiscPct + callerPurchLine.LinePercent;
        priceAfterDiscPercent                   = priceAfterCashDisc - (priceAfterCashDisc * totalDiscPct) / 100;
        TmpInventTransWMS.ETGRateCardDiscPct    = rateCardMaster.DiscPct;
