public void linkActive()
{
    movement = null;
    movement = element.movement();

    if (inventTransWMS_Register)
    {
        inventTransWMS_Register.makeTableEmpty();
    }
    element.inventTransWMS_Register(true);

    tmpInventTransWMS_DS.executeQuery();

    element.updateDesign(InventDimFormDesignUpdate::Init);
    createTransSerialNumber.enabled(inventTransWMS_Register && inventTransWMS_Register.canUpdateTransSerialId(inventTrans, movement, inventTransOriginMovement) ? true : false);
    interCompany.enabled(inventTransWMS_Register && inventTransOriginMovement.interCompanyOrder());
    super();

    //The form is closed if the inventTrans record does not exist.
    //This scenario could be invoked when scrolling through - to a non-inventoried purchase order line - on the purchase order form.
    if (!inventTransOriginMovement.RecId)
    {
        element.close();
    }
    if (#PdsShelfEnabled)
    {
        pdsResetDispositionStatus.enabled(InventTable::find(inventTransOriginMovement.ItemId).isItemBatchActivated());
    }

    if (cwFormCtrl)
    {
        cwFormCtrl.itemDataSourceActivePost();
    }
}

public display InventQtyRegisterRemain registerRemain()
{
    return inventTransWMS_Register ? (inventTransWMS_Register.registerRemain(movement)) : 0;
}

public display InventQtyOrdered ordered()
{
    return element.movement() ? element.movement().transIdSum().ordered() : 0;
}

public void executeQuery()
{
    InventTransferLine      inventTransferLine;
    InventTransferJourLine  inventTransferJourLine;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds = inventTransOriginMovement_DS.query().dataSourceTable(tableNum(InventTransOrigin));
    qbr = SysQuery::findOrCreateRange(qbds, fieldNum(InventTransOrigin,RecId));

    switch (element.args().dataset())
    {
        case tableNum(InventTransferLine):
            inventTransferLine = element.args().record() as InventTransferLine;
            qbds.clearDynalinks();
            qbr.value(queryValue(InventTransOriginTransferReceive::findInventTransOriginId(
                inventTransferLine.DataAreaId,
                inventTransferLine.TransferId,
                inventTransferLine.LineNum)));
            break;
        case tableNum(InventTransferJourLine):
            inventTransferJourLine = element.args().record() as InventTransferJourLine;
            qbds.clearDynalinks();
            qbr.value(queryValue(InventTransOriginJournalTransReceipt::findInventTransOriginId(
                inventTransferJourLine.DataAreaId,
                inventTransferJourLine.TransferId,
                inventTransferLine.LineNum)));
            break;
        default:
            InventTransFormHelper::formQueryPreExecute(
                inventTransOriginMovement_DS,
                inventTransExists_DS,
                element.args());
            break;
    }

    super();
}

display UnitIDInventory inventUnit()
{
    return InventTableModule::find(InventTransOriginMovement.ItemId, ModuleInventPurchSales::Invent).UnitId;
}

public void init()
{
    QueryBuildDataSource    qbds;

    super();

    inventTransExists_DS.query().dataSourceTable(tableNum(InventTrans)).clearDynalinks();

    InventTransFormHelper::formQueryAddDynalink(
        inventTransOriginMovement_DS,
        inventTransExists_DS,
        element.args());

    qbds = this.query().dataSourceTable(tableNum(InventTrans));
    qbds.addRange(fieldNum(InventTrans, StatusIssue)).value('0');

    if (element.args().dataset() == tableNum(InventQuarantineOrder))
    {
        qbds.addRange(fieldNum(InventTrans,StatusReceipt)).value(SysQuery::range(StatusReceipt::Registered,StatusReceipt::QuotationReceipt));
    }
}

public void clicked()
{
    InventTrans marked = inventTrans_ds.getFirst(1);

    if (marked)
    {
        do
        {
            element.autoTmpCreate(marked);

            marked = inventTrans_ds.getNext();
        }
        while (marked);
    }
    else
    {
        element.autoTmpCreate(inventTrans);
    }
}

public void clicked()
{
    TmpInventDim_ds.write();

    //CS - Abhinav - Validate rate card lines with elevator recceipt
    Purchtable PurchTableCheck = callerPurchLine.purchTable();
    if(ETGCanadaParameters::find().EnableRateCardChanges && PurchTableCheck.ETGElevatorReceiptNumber)
    {
        TmpInventTransWMS_ds.write();
        this.validateRateCardItemsWithElevatorReceipt(callerPurchLine,TmpInventTransWMS_ds);
    }
    //CE

    ETGPurchRateCardUtil obj = ETGPurchRateCardUtil::construct();
    obj.parmPurchLine(callerPurchLine);
    obj.parmPurchParmLine(callerPurchParmLine);
    obj.parmInventDim(TmpInventDim);
    obj.parmFormDataSource(TmpInventTransWMS_ds);
    obj.parmCalledFromProductReceipt(calledFromProductReceipt);
    obj.run();

    element.close();
}

// CS - Abhinav - Validate rate card lines
public void validateRateCardItemsWithElevatorReceipt(PurchLine _purchLine,FormDataSource fds)
{
    PurchTable                          purchTable = _purchLine.purchTable();
    TmpInventTransWMS                   inventTransWMS,inventTransWMSLoop;
    DataAreaId                          CurrentCompany = curExt();

    changecompany(purchTable.ETGERNEntity)
    {
        ETGElevatorReceiptGrainItemTable    etgElevatorReceiptGrainItemTable;
        ETGElevatorReceiptSplitsItemTable   etgElevatorReceiptSplitsItemTable;
        ETGElevatorReceiptTable             etgElevatorReceiptTable;

        select firstonly etgElevatorReceiptTable
            where etgElevatorReceiptTable.ElevatorReceiptNumber == purchTable.ETGElevatorReceiptNumber;

        //Check if all grain items selected if any
        while select etgElevatorReceiptGrainItemTable
            where etgElevatorReceiptGrainItemTable.ElevatorReceiptNumber == purchTable.ETGElevatorReceiptNumber
        {
            changecompany(CurrentCompany)
            {
                inventTransWMS = fds.getFirst() as TmpInventTransWMS;

                while(inventTransWMS.ItemId)
                {
                    if(inventTransWMS.ItemId == etgElevatorReceiptGrainItemTable.ItemId)
                    {
                        break;
                    }
                    inventTransWMS = fds.getNext() as TmpInventTransWMS;
                }

                if(!inventTransWMS.ItemId)
                {
                    throw error(strFmt("@ETG_New:GrainItemRateCardValidation",etgElevatorReceiptGrainItemTable.ItemId,purchTable.ETGElevatorReceiptNumber));
                }
                else
                {
                    if(inventTransWMS.InventQty != decround(etgElevatorReceiptGrainItemTable.GrainQty, 3))
                    {
                        throw error(strFmt("@ETG_New:RateCardERNQtyValidation",etgElevatorReceiptGrainItemTable.ItemId,purchTable.ETGElevatorReceiptNumber));
                    }
                }
            } 
        }

        //Check if all splits items selected if any
        while select etgElevatorReceiptSplitsItemTable
            where etgElevatorReceiptSplitsItemTable.ElevatorReceiptNumber == purchTable.ETGElevatorReceiptNumber
        {
            changecompany(CurrentCompany)
            {

                inventTransWMS = fds.getFirst() as TmpInventTransWMS;

                while(inventTransWMS.ItemId)
                {
                    if(inventTransWMS.ItemId == etgElevatorReceiptSplitsItemTable.ItemId)
                    {
                        break;
                    }
                    inventTransWMS = fds.getNext() as TmpInventTransWMS;
                }

                if(!inventTransWMS.ItemId)
                {
                    throw error(strFmt("@ETG_New:SplitsItemRateCardValidation",etgElevatorReceiptSplitsItemTable.ItemId,purchTable.ETGElevatorReceiptNumber));
                }
                else
                {
                    if(inventTransWMS.InventQty != decround(((etgElevatorReceiptTable.GrainUnloadedWeight * etgElevatorReceiptSplitsItemTable.SplitsPercentage ) / 100),3))
                    {
                        throw error(strFmt("@ETG_New:RateCardERNQtyValidation",etgElevatorReceiptSplitsItemTable.ItemId,purchTable.ETGElevatorReceiptNumber));
                    }
                }
            }
        }

        //Check if dockage item is selected if any

        if(etgElevatorReceiptTable.DockageGrain)
        {
            changecompany(CurrentCompany)
            {
                inventTransWMS = fds.getFirst() as TmpInventTransWMS;

                while(inventTransWMS.ItemId)
                {
                    if(inventTransWMS.ItemId == etgElevatorReceiptTable.DockageGrain)
                    {
                        break;
                    }
                    inventTransWMS = fds.getNext() as TmpInventTransWMS;
                }

                if(!inventTransWMS.ItemId)
                {
                    throw error(strFmt("@ETG_New:DockageItemrateCardValidation",etgElevatorReceiptTable.DockageGrain,purchTable.ETGElevatorReceiptNumber));
                }
                else
                {
                    if(inventTransWMS.InventQty != decround(etgElevatorReceiptTable.DockageWeight,3))
                    {
                        throw error(strFmt("@ETG_New:RateCardERNQtyValidation",etgElevatorReceiptTable.DockageGrain,purchTable.ETGElevatorReceiptNumber));
                    }
                }
            }
        }
    }
}
